var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"제6 방위선 함락 후, 72시간 경과","JPN":"第6防衛線陥落後、72時間経過","ENG":"72 hours after the fall of the 6th Defense Line","TWN":"第六防線淪陷後經過72小時"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제5 방위선\\n<color=#ffd34c>아포리아 공략 작전 수행 중</color>","JPN":"人類統合防衛軍第5防衛線\\n<color=#ffd34c>アポリア攻略作戦遂行中</color>","ENG":"United Humankind Defense Force's 5th Defense Line\\n<color=#ffd34c>Operation Aporia in progress</color>","TWN":"人類共同保衛軍第五防線\\n<color=#ffd34c>執行攻陷阿波利亞作戰中</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음, 그런데 박사님.","JPN":"ふむ……ところで博士。","ENG":"Hmm, but Doc.","TWN":"唔，博士。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"정말로 아포리아가 우리 생각대로 여길 공격하러 올까요?","JPN":"本当にアポリアが私たちの予想通り、ここを攻めてきますかね？","ENG":"Do you really believe Aporia will come and attack this area, like we imagined?","TWN":"阿波利亞真的會像我們預想的一樣攻擊這裡嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"여기가 아니라, 다른 곳에 갔으면 우리 작전은 실패하는 거잖아요.","JPN":"ここじゃないどこかに行かれてしまったら、私たちの作戦は失敗じゃないですか。","ENG":"If it went somewhere else, then our operation would be a bust.","TWN":"萬一他不來這裡，而是去其他地方的話，那我們的作戰可就失敗了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"재수없는 소리 하지 마.","JPN":"縁起の悪いこと言うなよ。","ENG":"Don't jinx it.","TWN":"少烏鴉嘴。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"녀석이 이끄는 침식체 무리는 항상 고치를 관리하는 관측소를 가장 먼저 습격했지.","JPN":"奴が率いる侵食体の群れは、毎回繭を管理する観測所から先に襲撃している。","ENG":"The C.O. horde it leads always attacked the cocoon observatory first.","TWN":"那傢伙帶領的侵蝕體群，總是最先攻擊保管繭的觀測站。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아마도 고치를 흡수할 때, 최대한 방해받지 않기 위해서일 거야.","JPN":"おそらく繭を吸収するときに、できるだけ邪魔が入らないようにするためだろうな。","ENG":"I think it's so it doesn't get disturbed while it absorbs the cocoon.","TWN":"也許是為了吸收繭的時候，盡量不受打擾。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"그러니까 이번에도 이곳 관측소부터 노려올 가능성이 커.","JPN":"だから今回も、この観測所を狙ってくる可能性は高い。","ENG":"So, it's highly likely that Aporia will come to this observatory.","TWN":"所以，這次襲擊這個觀測站的可能性很高。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"흐음, 하지만 괜찮을까요, 카린 양?","JPN":"ふむ……でも大丈夫なんですかね、カリンさん？","ENG":"Hmm, but are you sure this will be okay, Karin?","TWN":"嗯，但是作戰能成功嗎，卡琳？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아포리아가 여길 노린다고 해도, 그 침식체에게는 통상 병기가 통하지 않잖아요.","JPN":"アポリアがここを攻めてきたとしても、あの侵食体に通常の兵器は効かないですよ。","ENG":"Even if Aporia comes here, none of our normal weapons can do any damage to him.","TWN":"就算阿波利亞襲擊了這裡，普通的兵器可對付不了那個侵蝕體。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"물론, 일반적인 병기라면 데미지를 주기 힘들겠죠.","JPN":"もちろん、一般的な兵器であれば、ダメージを与えるのは難しいでしょうね。","ENG":"Yes, it will be difficult to harm him with ordinary weapons.","TWN":"沒錯，如果是普通的兵器無法對他造成傷害。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이번에 사용할 <color=#ffd34c>이터니움 반응 탄두 미사일</color>, 서른두 발은…….","JPN":"今回使用する<color=#ffd34c>エタニウム反応弾道ミサイル</color>、32発は……","ENG":"But the 32 shots of <color=#ffd34c>Eternium-reactive warhead missiles</color> we'll be using this time...","TWN":"這次對付他要用的是<color=#ffd34c>永恆之金反應導彈</color>，32枚……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"원래라면 각각 연구중인 시험용 함선의 엔진을 개조해서 만든 미사일이에요.","JPN":"本来であれば、各々が研究中の実験用艦船のエンジンとなるはずでした。ミサイルはそれを改造したもの。","ENG":"The missiles were manufactured using modified engines from test ships that were originally built for research purposes.","TWN":"每個都是由研究中試驗艦船的引擎改造而成。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"미래를 소모시킨 미사일 서른 두발이 지금 인류가 가용할 수 있는 최대 화력이고요.","JPN":"つまり、未来を削って生み出したミサイル32発が、現在の人類に使用できる最大の火力なんです。","ENG":"Right now, humanity's only weapons are the 32 missiles created by sacrificing the future.","TWN":"這32枚導彈是我們目前可使用的最強火力，預支的是人類的未來。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그 말은, 이 작전이 실패하면 다시는 그 이상의 화력을 기대할 수 없다는 이야기네요?","JPN":"ってことは、この作戦が失敗したら二度とそれ以上の火力は期待できないということですよね？","ENG":"So you're saying that if this operation fails, we can never expect any more firepower?","TWN":"你的意思是，如果這次作戰失敗的話，就不會有更強的火力了？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네, 그래서 기회는 단 한 번뿐입니다.","JPN":"はい、だからチャンスは一度きりです。","ENG":"Correct. This is our one and only chance.","TWN":"是的，所以機會只有一次。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"제이콥 씨가 제공해주신 정보로 6 방위선 대원 수백 명이 목숨을 바쳐가면서 아포리아의 약점을 알아냈어요.","JPN":"ジェイコブさんが提供してくださった情報、そして第6防衛線の隊員数百名の犠牲と引き換えに、アポリアの弱点を特定することができました。","ENG":"With intel provided by Officer Jacob, hundreds of soldiers from the 6th Defense Line have sacrificed their lives to uncover Aporia's weakness.","TWN":"透過雅各提供的情報，犧牲第六防線數百名隊員的生命，才發現到阿波利亞的弱點。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아포리아는 네피림 유체에서 핵을 흡수할 때, 잠깐이지만 자신의 핵을 노출한다고 해요.","JPN":"アポリアはネフィリムの幼体から核を吸収する際、一瞬ですが核が剥き出しになるそうです。","ENG":"When it absorbs the Nephil larva's core, it briefly exposes its own core as well.","TWN":"阿波利亞吸收諾菲力幼體的核心時，會短暫地暴露自己的核心。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리는 그 순간을 노려야 합니다. 실패는 용납되지 않아요.","JPN":"私たちはその瞬間を狙わないといけません。失敗は許されませんよ。","ENG":"That's when we strike. Failure will not be tolerated.","TWN":"我們要把握住那個瞬間。絕不能失敗。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"자, 잠깐!","JPN":"ちょ、ちょっと待って！","ENG":"W-wait!","TWN":"等，等等！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"네놈들끼리 지지든, 볶든 알 바 아니야!","JPN":"あんたたちが何をどうしようが、俺には関係ねえ！","ENG":"Whatever you all are doing, it's none of my business!","TWN":"你們這些傢伙輸也好，贏也好，都不關我的事！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"근데 왜 나까지 잡고 늘어지는 건데! 내 역할은 정보원으로 끝난 거 아니었어!?","JPN":"何で俺まで巻き込もうとするんだ！　俺の役目は情報提供までのはずだろう！？","ENG":"But why are you dragging me into this?! My role as the informant has ended already!","TWN":"但為什麼要抓著我不放啊！我已經完成情報員的工作了！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"제이콥 씨. 굉장히 유감스럽지만……","JPN":"ジェイコブさん。非常に残念ですが……","ENG":"Officer Jacob, I'm terribly sorry, but...","TWN":"雅各，非常遺憾……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"지금으로부터 72시간 전, 방위군 통합 정부는 초유의 비상사태에 의거 카운터 총동원령을 내렸습니다.","JPN":"今から72時間前、防衛軍統合政府から前例の無い非常事態につき、カウンター総動員命令が下されました。","ENG":"Due to the unprecedented emergency on hand, the United Humankind Government mobilized all Counters 72 hours ago.","TWN":"距離現在72小時前，保衛軍聯合政府已經針對史無前例的緊急情況下達制裁者總動員令。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그리고 제이콥 씨도 일단은 카운터로 등록되어 있더군요.","JPN":"そしてジェイコブさんも一応、カウンターとして登録されているようですね。","ENG":"And you, Officer Jacob, are registered as a Counter.","TWN":"雅各作為制裁者也登記在冊。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"뭐, 뭐라고!?","JPN":"な、何だと！？","ENG":"W-what?!","TWN":"什，什麼！？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"어이, 웃기지 말라고!","JPN":"おい、ふざけんじゃねえ！","ENG":"Hey, this isn't funny!","TWN":"喂，開什麼玩笑！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"기껏 방위군을 위해 중요 정보를 제공했는데 이딴 식으로 뒤통수를 쳐!?","JPN":"こっちは親切に防衛軍のためにとっておきの情報を提供したのに、こんな風に裏切るのか！？","ENG":"I get vital information for the Defense Force and you all stab me in the back like this?!","TWN":"我為了保衛軍盡心盡力地提供重要情報，結果你們卻這樣對待我！？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"에이, 너무 섭섭해하지 말라고. 원래 공무원이 까라면 까는 거지.","JPN":"まあ、そう寂しがるなよ。もともと公務員なんて政府の犬なんだからさ。","ENG":"C'mon, don't be so upset. It's all part of being a civil servant.","TWN":"喂，別太傷心，本來公務員就是用來剝削的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L43_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"난 카운터가 아니라서, 여기서 버튼만 누를 거지만 말이야.","JPN":"僕はカウンターじゃないから、ここからボタンを押すだけなんだけどね。","ENG":"And since I'm not a Counter, I'll be back here pressing buttons.","TWN":"我不是制裁者，不是還得留在這裡按按鈕嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"그래요, 어차피 이 작전이 실패하면 우리 모두 끝장이라고요.","JPN":"そうですよ、どうせこの作戦が失敗したら、私たちは皆死ぬんですから。","ENG":"Yeah, if this fails, we're all gonna die anyway.","TWN":"不錯，反正這次作戰失敗的話，我們全部都得完蛋。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아무것도 못 하고 후회하면서 죽을 바에는 차라리 저희와 함께 싸우는 편이 낫지 않겠어요?","JPN":"何もできずに死ぬくらいなら、いっそ私たちと一緒に戦って死んだ方がマシじゃありませんか？","ENG":"So wouldn't it be better to fight or die trying than have regrets about doing nothing?","TWN":"與其什麼都不做，然後冤枉地死去，不如和我們一起並肩戰鬥來得好?"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"이, 이이……!","JPN":"この……この……！","ENG":"Why, you...!","TWN":"這，這這……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"이런, 제기랄! 정말이지 웃기지도 않는 촌극이군!","JPN":"この、くそが！　まったく笑えない茶番だぜ！","ENG":"Dammit! This is ridiculous, you hear?!","TWN":"該死！真是讓人無言的鬧劇！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"잊지 마, 이 개자식들아! 나는 죽어도 절대 혼자서는 안 죽을 테니까!","JPN":"覚えておけよ、このくそども！　俺は死んだとしても絶対一人じゃ死なないからな！","ENG":"Mark my words, you lunatics! If I go down, I'm not going alone!","TWN":"聽好了，你們這群瘋子！要是我死的話，也要拉你們當墊背的！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"소령님! 목표가 이쪽을 향해 접근하고 있습니다.","JPN":"少佐！　ターゲットがこちらに接近してきています。","ENG":"Major! The target is approaching us.","TWN":"少校！目標正在朝我們這個方向接近。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"좋습니다. 전 대원, 각자 정해진 위치로 가주세요!","JPN":"わかりました。全隊員、配置についてください！","ENG":"Good. All units, to your positions!","TWN":"很好，全體隊員，請前往各自指定的位置！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"기회는 단 한 번! 아포리아가 네피림 고치를 찢고 네피림의 핵을 흡수하는 순간입니다!","JPN":"チャンスは一度きり！　アポリアがネフィリムの繭を破ってネフィリムの核を吸収する瞬間です！","ENG":"We only have one chance! We strike when Aporia rips open the cocoon and absorbs its core!","TWN":"機會只有一次！阿波利亞撕開諾菲力繭，吸收核心的那個瞬間！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 순간이 오기 직전까지 각자 위치를 사수해주세요!","JPN":"その瞬間まではそれぞれの位置を死守してください！","ENG":"Until then, everyone is to stay in position!","TWN":"在那之前，請堅守在各自的位置！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT1","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};